import{_ as e,o as a,c as d,ai as i}from"./chunks/framework.DyvBZb4W.js";const l="/jasonsong-games/images/knowledge/sts2/events/aroma_of_chaos.webp",c="/jasonsong-games/images/knowledge/sts2/events/byrdonis_nest.webp",n="/jasonsong-games/images/knowledge/sts2/events/dense_vegetation.webp",r="/jasonsong-games/images/knowledge/sts2/events/jungle_maze_adventure.webp",v="/jasonsong-games/images/knowledge/sts2/events/luminous_choir.webp",_="/jasonsong-games/images/knowledge/sts2/events/morphic_grove.webp",o="/jasonsong-games/images/knowledge/sts2/events/sapphire_seed.webp",t="/jasonsong-games/images/knowledge/sts2/events/sunken_statue.webp",g="/jasonsong-games/images/knowledge/sts2/events/tablet_of_truth.webp",p="/jasonsong-games/images/knowledge/sts2/events/unrest_site.webp",m="/jasonsong-games/images/knowledge/sts2/events/wellspring.webp",y="/jasonsong-games/images/knowledge/sts2/events/whispering_hollow.webp",b="/jasonsong-games/images/knowledge/sts2/events/wood_carvings.webp",h="/jasonsong-games/images/knowledge/sts2/events/abyssal_baths.webp",w="/jasonsong-games/images/knowledge/sts2/events/drowning_beacon.webp",k="/jasonsong-games/images/knowledge/sts2/events/endless_conveyor.webp",u="/jasonsong-games/images/knowledge/sts2/events/punch_off.webp",z="/jasonsong-games/images/knowledge/sts2/events/spiraling_whirlpool.webp",j="/jasonsong-games/images/knowledge/sts2/events/sunken_treasury.webp",f="/jasonsong-games/images/knowledge/sts2/events/doors_of_light_and_dark.webp",x="/jasonsong-games/images/knowledge/sts2/events/trash_heap.webp",q="/jasonsong-games/images/knowledge/sts2/events/waterlogged_scriptorium.webp",P="/jasonsong-games/images/knowledge/sts2/events/amalgamator.webp",B="/jasonsong-games/images/knowledge/sts2/events/bugslayer.webp",S="/jasonsong-games/images/knowledge/sts2/events/colorful_philosophers.webp",A="/jasonsong-games/images/knowledge/sts2/events/colossal_flower.webp",M="/jasonsong-games/images/knowledge/sts2/events/field_of_man_sized_holes.webp",T="/jasonsong-games/images/knowledge/sts2/events/infested_automaton.webp",E="/jasonsong-games/images/knowledge/sts2/events/lost_wisp.webp",N="/jasonsong-games/images/knowledge/sts2/events/spirit_grafter.webp",C="/jasonsong-games/images/knowledge/sts2/events/the_lantern_key.webp",D="/jasonsong-games/images/knowledge/sts2/events/zen_weaver.webp",$="/jasonsong-games/images/knowledge/sts2/events/battleworn_dummy.webp",O="/jasonsong-games/images/knowledge/sts2/events/grave_of_the_forgotten.webp",U="/jasonsong-games/images/knowledge/sts2/events/hungry_for_mushrooms.webp",V="/jasonsong-games/images/knowledge/sts2/events/reflections.webp",G="/jasonsong-games/images/knowledge/sts2/events/round_tea_party.webp",I="/jasonsong-games/images/knowledge/sts2/events/trial.webp",R="/jasonsong-games/images/knowledge/sts2/events/tinker_time.webp",H="/jasonsong-games/images/knowledge/sts2/events/brain_leech.webp",J="/jasonsong-games/images/knowledge/sts2/events/crystal_sphere.webp",F="/jasonsong-games/images/knowledge/sts2/events/doll_room.webp",K="/jasonsong-games/images/knowledge/sts2/events/fake_merchant.webp",L="/jasonsong-games/images/knowledge/sts2/events/potion_courier.webp",Q="/jasonsong-games/images/knowledge/sts2/events/ranwid_the_elder.webp",W="/jasonsong-games/images/knowledge/sts2/events/relic_trader.webp",X="/jasonsong-games/images/knowledge/sts2/events/room_full_of_cheese.webp",Y="/jasonsong-games/images/knowledge/sts2/events/self_help_book.webp",Z="/jasonsong-games/images/knowledge/sts2/events/slippery_bridge.webp",ss="/jasonsong-games/images/knowledge/sts2/events/stone_of_all_time.webp",ts="/jasonsong-games/images/knowledge/sts2/events/symbiote.webp",es="/jasonsong-games/images/knowledge/sts2/events/tea_master.webp",as="/jasonsong-games/images/knowledge/sts2/events/the_future_of_potions.webp",ds="/jasonsong-games/images/knowledge/sts2/events/the_legends_were_true.webp",is="/jasonsong-games/images/knowledge/sts2/events/this_or_that.webp",ls="/jasonsong-games/images/knowledge/sts2/events/war_historian_repy.webp",cs="/jasonsong-games/images/knowledge/sts2/events/welcome_to_wongos.webp",ns="/jasonsong-games/images/knowledge/sts2/acts-map-events-flow.svg",bs=JSON.parse('{"title":"杀戮尖塔2 地图区域影响哪些随机结果","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge/sts2/acts-map-events.md","filePath":"knowledge/sts2/acts-map-events.md","lastUpdated":1778402328000}'),rs={name:"knowledge/sts2/acts-map-events.md"};function vs(_s,s,os,gs,ps,ms){return a(),d("div",null,[...s[0]||(s[0]=[i('<h1 id="杀戮尖塔2-地图区域影响哪些随机结果" tabindex="-1">杀戮尖塔2 地图区域影响哪些随机结果 <a class="header-anchor" href="#杀戮尖塔2-地图区域影响哪些随机结果" aria-label="Permalink to &quot;杀戮尖塔2 地图区域影响哪些随机结果&quot;">​</a></h1><p>这篇回答一个很具体的问题：在 STS2 里，密林、暗港、巢穴、荣耀这些地图区域，会不会改变问号、事件、怪物和 Boss 的随机结果？</p><p>简短版：</p><ul><li>地图区域会改变：地图长度、问号数量、事件池、普通怪池、精英池、Boss 池、先民池、背景和音乐。</li><li>地图区域不直接改变：问号翻成“事件 / 普通战斗 / 商店 / 宝箱”的基础 odds。</li><li>所以你会感觉“不同地图的问号不一样”，主要原因不是问号概率表换了，而是问号数量不同，且问号变成事件后抽的是当前区域的事件池。</li></ul><h2 id="先分清两个-地图" tabindex="-1">先分清两个“地图” <a class="header-anchor" href="#先分清两个-地图" aria-label="Permalink to &quot;先分清两个“地图”&quot;">​</a></h2><p>玩家讨论“地图”时，通常混着说两件事：</p><table tabindex="0"><thead><tr><th>说法</th><th>实际指什么</th><th>会影响什么</th></tr></thead><tbody><tr><td>“这一幕是密林 / 暗港 / 巢穴 / 荣耀”</td><td>区域，源码里是 act</td><td>房间数、问号数、事件池、怪物池、Boss 池等。</td></tr><tr><td>“这个问号会变成什么”</td><td>问号节点翻开时的房间类型 roll</td><td>使用一套全局基础 odds，并随本局问号历史动态变化。</td></tr></tbody></table><p>后面所有结论都按这两层拆开讲。</p><h2 id="区域影响事件池" tabindex="-1">区域影响事件池 <a class="header-anchor" href="#区域影响事件池" aria-label="Permalink to &quot;区域影响事件池&quot;">​</a></h2><p>问号房先 roll 房间类型。只有当它 roll 成“事件”后，游戏才会从事件队列里取具体事件。</p><p>这个事件队列不是全游戏事件混在一起抽，而是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前区域专属事件 + 共享事件 - 尚未解锁的事件</span></span></code></pre></div><p>这里的“共享事件”还要再分两种：</p><ul><li><strong>区域列表复用</strong>：某个事件被写进多个区域的事件列表。当前明显的例子是 <strong>沉没雕像</strong>，它同时在密林和暗港。</li><li><strong>全区域共享事件</strong>：<code>ModelDb.AllSharedEvents</code> 里的事件，会追加到每个区域的事件池里。比如水晶球、茶艺大师、遗物交换商等。</li></ul><p>也就是说，在密林走问号时，如果问号变成事件，候选池大致是“密林区域事件 + 全区域共享事件”；在暗港则是“暗港区域事件 + 全区域共享事件”。如果事件还没解锁，或当前状态不满足事件出现条件，游戏会跳过它。</p><p>下面的事件图来自本地游戏资源导出的事件插图；<strong>灯火钥匙</strong>没有标准事件背景图，这里用的是游戏里的灯火钥匙任务图。</p><h3 id="密林区域事件" tabindex="-1">密林区域事件 <a class="header-anchor" href="#密林区域事件" aria-label="Permalink to &quot;密林区域事件&quot;">​</a></h3><p>密林的事件池偏“植物、异鸟、森林遗迹、泉水、迷路与变化”。其中 <strong>沉没雕像</strong> 也会在暗港出现。</p><div class="sts2-event-grid"><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+l+'" alt="混沌芳香事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">变化 / 升级</div><div class="sts2-event-card__title">混沌芳香</div><p>在“变化一张牌”和“升级一张牌”之间选。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+c+'" alt="多尼斯异鸟巢事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">最大生命 / 卡牌</div><div class="sts2-event-card__title">多尼斯异鸟巢</div><p>吃蛋获得最大生命，或带走蛋获得相关卡牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+n+'" alt="茂密的植被事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">删牌 / 回复后战斗</div><div class="sts2-event-card__title">茂密的植被</div><p>硬穿植被可删牌但掉血；休息会回血并进入战斗。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+r+'" alt="丛林迷宫奇遇事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 掉血换更多金币</div><div class="sts2-event-card__title">丛林迷宫奇遇</div><p>和冒险小队同行拿较少金币；独自挑战拿更多金币但掉血。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+v+'" alt="冷光合唱团事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">遗物 / 删牌加牌</div><div class="sts2-event-card__title">冷光合唱团</div><p>付金币拿随机遗物，或删 2 张牌并加入孢子心灵。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+_+'" alt="变形灵林谷事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">变化 / 最大生命</div><div class="sts2-event-card__title">变形灵林谷</div><p>花金币变化 2 张牌，或获得最大生命。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+o+'" alt="蓝宝石种子事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">回复升级 / 附魔</div><div class="sts2-event-card__title">蓝宝石种子</div><p>回复并升级一张牌，或给牌加种子相关附魔。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+t+'" alt="沉没雕像事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 遗物</div><div class="sts2-event-card__title">沉没雕像</div><p>潜水拿金币但掉血，或拿石剑遗物。也在暗港事件池中。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+g+'" alt="真理石板事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">回复 / 高风险升级</div><div class="sts2-event-card__title">真理石板</div><p>砸碎回复；持续解读会用最大生命换升级，最后可升级全部卡牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+p+'" alt="无休之处事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">全回复负面牌 / 掉最大生命拿遗物</div><div class="sts2-event-card__title">无休之处</div><p>休息会满血但获得睡眠不佳；处理树木会掉最大生命换遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+m+'" alt="泉水事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">药水 / 删牌加诅咒</div><div class="sts2-event-card__title">泉水</div><p>装瓶拿随机药水；沐浴删牌但加入愧疚。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+y+'" alt="低语空谷事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">药水 / 变化</div><div class="sts2-event-card__title">低语空谷</div><p>给金币换 2 瓶药水，或掉血变化一张牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+b+'" alt="木雕事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">初始牌变化 / 附魔</div><div class="sts2-event-card__title">木雕</div><p>鸟或圆环会把初始牌变化成特殊牌；蛇会给一张牌加蛇行附魔。</p></div></article></div><h3 id="暗港区域事件" tabindex="-1">暗港区域事件 <a class="header-anchor" href="#暗港区域事件" aria-label="Permalink to &quot;暗港区域事件&quot;">​</a></h3><p>暗港的事件池偏“水、宝藏、商店式交易、构装体、漩涡与沉没遗迹”。其中 <strong>沉没雕像</strong> 与密林共享。</p><div class="sts2-event-grid"><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+h+'" alt="深渊浴场事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">回复 / 最大生命换伤害</div><div class="sts2-event-card__title">深渊浴场</div><p>敬而远之回复；投身池水获得最大生命但受伤，可继续沉溺。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+w+'" alt="淹水灯塔事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">药水 / 遗物换最大生命</div><div class="sts2-event-card__title">淹水灯塔</div><p>装瓶拿药水；攀爬拿遗物但失去最大生命。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+k+'" alt="无尽传送带事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币消费 / 多种小奖励</div><div class="sts2-event-card__title">无尽传送带</div><p>观察主厨可升级牌；花金币吃不同菜，可能获得金币、药水、变化、升级、最大生命等。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+u+'" alt="重拳出击事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">遗物 / 战斗</div><div class="sts2-event-card__title">重拳出击</div><p>偷拿遗物会得到伤口；也可以直接开战换更好奖励。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+z+'" alt="螺旋漩涡事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">回复 / 附魔 / 遗物加诅咒</div><div class="sts2-event-card__title">螺旋漩涡</div><p>饮用回复；观察给打击或防御附魔；伸手拿遗物但加入负面牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+t+'" alt="沉没雕像事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 遗物</div><div class="sts2-event-card__title">沉没雕像</div><p>潜水拿金币但掉血，或拿石剑遗物。也在密林事件池中。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+j+'" alt="淹水金库事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 诅咒换更多金币</div><div class="sts2-event-card__title">淹水金库</div><p>开小箱拿少量金币；开大箱拿更多金币但得到贪婪。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+f+'" alt="光与暗的门扉事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">删牌 / 升级</div><div class="sts2-event-card__title">光与暗的门扉</div><p>暗之门删 1 张牌；光之门随机升级多张牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+x+'" alt="垃圾堆事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币旧牌 / 旧日遗物</div><div class="sts2-event-card__title">垃圾堆</div><p>表层拿金币和旧日卡牌；深入掉血拿旧日遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+q+'" alt="水漫缮写室事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">最大生命 / 稳定附魔</div><div class="sts2-event-card__title">水漫缮写室</div><p>血液墨水给最大生命；付金币给一张或多张牌加稳定附魔。</p></div></article></div><h3 id="巢穴区域事件" tabindex="-1">巢穴区域事件 <a class="header-anchor" href="#巢穴区域事件" aria-label="Permalink to &quot;巢穴区域事件&quot;">​</a></h3><p>巢穴的事件池偏“虫群、寄生、融合、灵魂、异变与跨角色牌”。整体更常见“拿强奖励，但同时改牌组结构或付出代价”。</p><div class="sts2-event-grid"><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+P+'" alt="熔合者事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">删基础牌 / 获得融合牌</div><div class="sts2-event-card__title">熔合者</div><p>移除 2 张打击或 2 张防御，换一张对应强牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+B+'" alt="害虫杀手事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">获得卡牌</div><div class="sts2-event-card__title">害虫杀手</div><p>在两张虫害主题卡牌之间选一张加入牌组。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+S+'" alt="色彩哲学家事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">跨角色牌 / 棱镜碎片</div><div class="sts2-event-card__title">色彩哲学家</div><p>选择角色颜色拿对应角色卡牌，或选择“平等”拿棱镜碎片。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+A+'" alt="巨大花卉事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 高风险遗物</div><div class="sts2-event-card__title">巨大花卉</div><p>逐步深入会持续掉血；可中途拿金币，也可摸到核心遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+M+'" alt="人形洞穴之地事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">附魔 / 删牌加诅咒</div><div class="sts2-event-card__title">人形洞穴之地</div><p>进入洞穴给牌附魔；抵抗诱惑可删牌但加入诅咒。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+T+'" alt="被寄生的自动机械事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">随机能力 / 随机 0 费牌</div><div class="sts2-event-card__title">被寄生的自动机械</div><p>研究拿随机能力牌；触碰核心拿随机 0 费牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+E+'" alt="迷失鬼火事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 诅咒换遗物</div><div class="sts2-event-card__title">迷失鬼火</div><p>搜索拿金币；抓鬼火会加诅咒并获得遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+N+'" alt="灵魂嫁接者事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">回复加牌 / 删牌</div><div class="sts2-event-card__title">灵魂嫁接者</div><p>接纳会回血并加入羽化；拒绝会掉血并删 1 张牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+C+'" alt="灯火钥匙事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 战斗</div><div class="sts2-event-card__title">灯火钥匙</div><p>交还钥匙拿金币；留下钥匙会进入战斗。它还会影响共享事件“战史学家 付袭”。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+D+'" alt="修禅织网者事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">花金币换删牌或加牌</div><div class="sts2-event-card__title">修禅织网者</div><p>付金币学习技巧，常见结果包括删 1-2 张牌，或加入开悟等。</p></div></article></div><h3 id="荣耀区域事件" tabindex="-1">荣耀区域事件 <a class="header-anchor" href="#荣耀区域事件" aria-label="Permalink to &quot;荣耀区域事件&quot;">​</a></h3><p>荣耀的区域事件最少，内容更偏“后期高波动”：战斗检测、复制牌组、判决、定制卡牌、强遗物和诅咒交换。</p><div class="sts2-event-grid"><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+$+'" alt="战痕累累的训练假人事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">限时战斗 / 奖励档位</div><div class="sts2-event-card__title">战痕累累的训练假人</div><p>选择不同生命值档位的假人战斗，奖励从药水、升级到随机遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+O+'" alt="遗忘之墓事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">遗物 / 诅咒加附魔</div><div class="sts2-event-card__title">遗忘之墓</div><p>接受灵魂拿遗物；直面真相会加诅咒，并给消耗牌附魔。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+U+'" alt="蘑菇饥渴事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">二选一遗物</div><div class="sts2-event-card__title">蘑菇饥渴</div><p>在大蘑菇和芳香蘑菇之间选；一个偏稳定，一个会带来伤害代价。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+V+'" alt="镜中倒影 影倒中镜事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">复制牌组 / 升降级</div><div class="sts2-event-card__title">镜中倒影 影倒中镜</div><p>打碎可复制整个牌组但获得霉运；触碰镜子会降级 2 张、升级 4 张。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+G+'" alt="圆桌茶会事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">全回复遗物 / 掉血拿遗物</div><div class="sts2-event-card__title">圆桌茶会</div><p>喝茶拿专属遗物并回满；挑事会掉血并拿随机遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+I+'" alt="审判事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">判决事件 / 多分支奖励</div><div class="sts2-event-card__title">审判</div><p>接受成为判决者，根据案件判有罪或无罪，奖励可能是金币、遗物、升级、变化，也可能加入诅咒。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+R+'" alt="打造时间事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">定制卡牌</div><div class="sts2-event-card__title">打造时间</div><p>选择卡牌类型和效果词条，制作一张定制卡加入牌组。</p></div></article></div><h3 id="全区域共享事件" tabindex="-1">全区域共享事件 <a class="header-anchor" href="#全区域共享事件" aria-label="Permalink to &quot;全区域共享事件&quot;">​</a></h3><p>这些事件来自全局共享事件列表，会追加到每个区域的事件池里。实际能不能出现，还会受解锁进度、当前牌组、金币、药水、遗物、生命值等条件影响。</p><div class="sts2-event-grid"><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+H+'" alt="脑蛭事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">卡牌奖励 / 掉血换无色牌</div><div class="sts2-event-card__title">脑蛭</div><p>分享知识可从随机牌中选牌；扯下来会掉血并拿无色牌奖励。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+J+'" alt="水晶球事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">付费占卜 / 诅咒占卜</div><div class="sts2-event-card__title">水晶球</div><p>花金币或拿诅咒换占卜次数，通过翻格子获得奖励或风险。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+F+'" alt="玩偶室事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">玩偶遗物</div><div class="sts2-event-card__title">玩偶室</div><p>直接拿随机玩偶遗物，或掉血从 2-3 个玩偶遗物里选。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+K+'" alt="商人？？？事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">特殊商店 / 可战斗</div><div class="sts2-event-card__title">商人？？？</div><p>一个事件版商店；通常围绕买遗物，也可能因特殊行为进入战斗。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+L+'" alt="药水快递员事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">药水</div><div class="sts2-event-card__title">药水快递员</div><p>拿污浊药水，或洗劫一瓶随机罕见药水。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+Q+'" alt="长者兰伟德事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">交换遗物</div><div class="sts2-event-card__title">长者兰伟德</div><p>给金币、药水或遗物，换随机遗物；给遗物通常换 2 件。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+W+'" alt="遗物交换商事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">以旧换新</div><div class="sts2-event-card__title">遗物交换商</div><p>用已有遗物换另一件遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+X+'" alt="满屋芝士事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">普通牌 / 专属遗物</div><div class="sts2-event-card__title">满屋芝士</div><p>从随机普通牌里选牌，或掉血拿天选芝士。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+Y+'" alt="自助指南事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">附魔</div><div class="sts2-event-card__title">自助指南</div><p>根据攻击、技能、能力牌条件，给对应牌加附魔。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+Z+'" alt="滑脚木桥事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">删牌 / 重 roll</div><div class="sts2-event-card__title">滑脚木桥</div><p>可以直接移除随机指定牌，也可以反复撑住，掉血并重 roll 可移除的牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+ss+'" alt="永恒之石事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">最大生命 / 攻击牌附魔</div><div class="sts2-event-card__title">永恒之石</div><p>喝药试抬石头换最大生命，或掉血给攻击牌加活力附魔。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+ts+'" alt="共生体事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">攻击牌附魔 / 变化</div><div class="sts2-event-card__title">共生体</div><p>靠近给攻击牌加腐化类附魔；烧掉则变化一张牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+es+'" alt="茶艺大师事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">花金币买茶</div><div class="sts2-event-card__title">茶艺大师</div><p>不同茶提供不同收益；也可以选择无礼之茶。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+as+'" alt="药水的未来？事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">药水换牌</div><div class="sts2-event-card__title">药水的未来？</div><p>失去一瓶药水，换一张升级过的对应稀有度/类型卡牌。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+ds+'" alt="传说是真的事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">藏宝图 / 药水</div><div class="sts2-event-card__title">传说是真的</div><p>拿藏宝图，或掉血慢慢找出口并拿随机药水。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+is+'" alt="这个还是那个？事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">金币 / 诅咒遗物</div><div class="sts2-event-card__title">这个还是那个？</div><p>拿钱袋会掉血拿金币；拿诅咒遗物会加诅咒并拿随机遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+ls+'" alt="战史学家 付袭事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">灯火钥匙联动</div><div class="sts2-event-card__title">战史学家 付袭</div><p>如果有灯火钥匙，可打开笼子拿历史课，或开宝箱拿多瓶药水和多件遗物。</p></div></article><article class="sts2-event-card"><img class="sts2-event-card__image" src="'+cs+'" alt="欢迎来到旺购百货事件插图" loading="lazy"><div class="sts2-event-card__body"><div class="sts2-event-card__type">特殊商店</div><div class="sts2-event-card__title">欢迎来到旺购百货</div><p>花金币买普通遗物、特选遗物或神秘盲盒；空手离开会随机降级一张牌。</p></div></article></div><h2 id="区域影响怪物、精英和-boss" tabindex="-1">区域影响怪物、精英和 Boss <a class="header-anchor" href="#区域影响怪物、精英和-boss" aria-label="Permalink to &quot;区域影响怪物、精英和 Boss&quot;">​</a></h2><p>每个区域都有自己的遭遇池：</p><ul><li>普通战斗取当前区域的普通怪队列。</li><li>精英战斗取当前区域的精英队列。</li><li>Boss 从当前区域 Boss 池里选；如果还有没见过的 Boss，会优先按发现顺序安排。</li></ul><p>这就是为什么同样是普通战斗图标，密林和暗港的敌人完全不同；同样是精英图标，背后的候选战斗也按区域换。</p><h2 id="区域影响地图长度和问号数量" tabindex="-1">区域影响地图长度和问号数量 <a class="header-anchor" href="#区域影响地图长度和问号数量" aria-label="Permalink to &quot;区域影响地图长度和问号数量&quot;">​</a></h2><p>区域还会改变这一幕有多少房间、多少问号、多少休息点：</p><table tabindex="0"><thead><tr><th>区域</th><th style="text-align:right;">基础房间数</th><th style="text-align:right;">问号节点数量</th><th style="text-align:right;">休息点数量</th></tr></thead><tbody><tr><td>密林</td><td style="text-align:right;">15</td><td style="text-align:right;">约 10-14</td><td style="text-align:right;">约 6-7</td></tr><tr><td>暗港</td><td style="text-align:right;">15</td><td style="text-align:right;">约 10-14</td><td style="text-align:right;">约 6-7</td></tr><tr><td>巢穴</td><td style="text-align:right;">14</td><td style="text-align:right;">约 9-13</td><td style="text-align:right;">约 6-7</td></tr><tr><td>荣耀</td><td style="text-align:right;">13</td><td style="text-align:right;">约 9-13</td><td style="text-align:right;">约 5-6</td></tr></tbody></table><p>多人模式下，每幕基础房间数会再少 1。</p><p>这点很重要：问号“翻成什么”的基础规则即使相同，区域也能通过问号数量改变你实际遇到事件、怪物、商店、宝箱的次数。</p><h2 id="区域影响地图节点分布" tabindex="-1">区域影响地图节点分布 <a class="header-anchor" href="#区域影响地图节点分布" aria-label="Permalink to &quot;区域影响地图节点分布&quot;">​</a></h2><p>标准地图大致有这些固定规则：</p><ul><li>第一排普通节点固定是普通战斗。</li><li>接近 Boss 前的一排固定是休息点。</li><li>中段有一排固定是宝箱；某些效果可能把这排宝箱替换成精英。</li><li>商店默认 3 个。</li><li>精英默认 5 个；高进阶的“蜂拥精英”会增加精英数量。</li><li>其余节点按区域配置补上休息点、问号、商店、精英，剩余空位变成普通战斗。</li></ul><p>游戏还会避免一些不舒服的排布，例如精英、休息点、宝箱、商店等不会轻易连续贴在父子节点上，休息点和精英也不会出现在太靠下的位置。</p><h2 id="问号概率不是按区域换表" tabindex="-1">问号概率不是按区域换表 <a class="header-anchor" href="#问号概率不是按区域换表" aria-label="Permalink to &quot;问号概率不是按区域换表&quot;">​</a></h2><p>问号房翻开时，基础 odds 大致如下：</p><table tabindex="0"><thead><tr><th>结果</th><th style="text-align:right;">基础 odds</th></tr></thead><tbody><tr><td>普通战斗</td><td style="text-align:right;">10%</td></tr><tr><td>宝箱</td><td style="text-align:right;">2%</td></tr><tr><td>商店</td><td style="text-align:right;">3%</td></tr><tr><td>事件</td><td style="text-align:right;">剩余概率，初始约 85%</td></tr><tr><td>精英</td><td style="text-align:right;">默认关闭</td></tr></tbody></table><p>这里容易误解：它不是每次都固定“85% 事件”。如果某个非事件结果这次没 roll 到，它的 odds 会增加；如果 roll 到了，它会回到基础值。事件概率是剩余概率，所以会随着怪物、宝箱、商店 odds 的累计而下降。</p><p>直观理解：连续几个问号都出事件后，后续问号出普通战斗、商店、宝箱的机会会逐步变高。出过一次普通战斗后，普通战斗 odds 又会回到基础值。</p><p>这套问号 odds 目前不是“密林一张表、暗港一张表、巢穴一张表”。区域影响的是两个更外层的东西：这幕地图有多少问号；问号变成事件后，从哪个事件队列取具体事件。</p><h2 id="路线规划时怎么用" tabindex="-1">路线规划时怎么用 <a class="header-anchor" href="#路线规划时怎么用" aria-label="Permalink to &quot;路线规划时怎么用&quot;">​</a></h2><ul><li>想多找区域专属事件，就多走当前区域问号；但问号不保证都是事件。</li><li>巢穴和荣耀的问号节点数量通常比密林、暗港少一点，所以“刷问号”的空间也少一点。</li><li>如果前面问号连续出事件，后面问号变成怪物、商店或宝箱的概率会变高。</li><li>不同区域的精英、Boss 和普通怪池不同，不能只看节点图标判断难度。</li><li>解锁进度会改变事件池和先民池；新档、老档、多人、Mod 环境都可能让结果不同。</li></ul><h2 id="底层实现原理" tabindex="-1">底层实现原理 <a class="header-anchor" href="#底层实现原理" aria-label="Permalink to &quot;底层实现原理&quot;">​</a></h2><blockquote><p>这一节是实现细节，不感兴趣可以跳过。前面已经覆盖路线规划需要知道的内容。</p></blockquote><figure class="rng-diagram"><img src="'+ns+'" alt="杀戮尖塔2 区域配置、地图生成、问号房和事件队列关系流程图"><figcaption>区域先决定本幕的事件池、遭遇池和地图规则；问号房再单独 roll 房间类型，只有 roll 成事件后才会从本幕事件队列取具体事件。</figcaption></figure><p>源码层面，区域由 <code>ActModel</code> 派生类定义。当前常见区域包括：</p><table tabindex="0"><thead><tr><th>区域</th><th>类</th><th>主要配置</th></tr></thead><tbody><tr><td>密林</td><td><code>Overgrowth</code></td><td>15 个基础房间、13 个专属事件、3 个弱战斗、3 个 Boss 候选。</td></tr><tr><td>暗港</td><td><code>Underdocks</code></td><td>15 个基础房间、10 个专属事件、3 个弱战斗、3 个 Boss 候选。</td></tr><tr><td>巢穴</td><td><code>Hive</code></td><td>14 个基础房间、10 个专属事件、2 个弱战斗、3 个 Boss 候选。</td></tr><tr><td>荣耀</td><td><code>Glory</code></td><td>13 个基础房间、7 个专属事件、2 个弱战斗、3 个 Boss 候选。</td></tr></tbody></table><p>开局默认区域列表是“密林、巢穴、荣耀”。暗港解锁后，有机会替换第一幕；如果暗港已解锁但还没被发现，非多人模式下会优先出现。</p><p>生成房间池时，游戏会：</p><ol><li>把当前区域的 <code>AllEvents</code> 和 <code>ModelDb.AllSharedEvents</code> 合并。</li><li>按解锁进度移除还没揭示的事件。</li><li>洗牌后放入本幕事件队列。</li><li>分别生成普通战斗队列、精英战斗队列、Boss、先民。</li><li>进入事件房时，取事件队列里的下一个有效事件，并记录已访问事件，尽量避免重复。</li></ol><p>标准地图由 <code>StandardActMap</code> 生成。地图 RNG 使用 <code>act_N_map</code> 从本局种子派生，因此同一种子、同一幕、同一游戏状态下，地图结构和节点分布更容易复现。</p><p>问号房 odds 由 <code>UnknownMapPointOdds</code> 维护。基础值是普通战斗 <code>0.10</code>、宝箱 <code>0.02</code>、商店 <code>0.03</code>、精英 <code>-1</code>，事件概率用 <code>1 - 正数非事件 odds 之和</code> 计算。每次问号 roll 后，roll 到的类型重置为基础值，没 roll 到的可用类型增加自己的基础值。</p>',62)])])}const hs=e(rs,[["render",vs]]);export{bs as __pageData,hs as default};
